#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {       vll a(7);    for(int i=0; i<7; i++) cin >> a[i];    sort(a.begin(), a.end());    ll sum=0;    for(int i=0; i<7-1; i++){        sum+=(-1*a[i]);    }    cout<<sum+a[6]<<"\n";} // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}